  // replace with real auth (JWT, session, etc.)
  if (!req.headers.authorization) return res.status(401).json({ error: 'Unauthorized' });
  next();
}

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', requireAuth, (req, res) => {
  res.json([{ id: 1, name: 'Alice' }, { id: 2, name: 'Bob' }]);
});

app.use((err, req, res, next) => {
  console.error(err);
  res.status(500).json({ error: 'Internal Server Error' });
});

const HOST = process.env.HOST || '127.0.0.1';
const PORT = Number(process.env.PORT) || 3000;
app.listen(PORT, HOST, () => console.log(`Server running on ${HOST}:${PORT}`));

module.exports = app;
```

### Priority
1. **High**: #1 (PII without auth) — fix before this endpoint is ever wired to real data.
2. **Medium**: #2, #4, #5 (helmet, rate limit, error handler/logging).
3. **Low**: #3, #6, #7, #8, #9 (hardening for future growth).

